import{g as o}from"./gas-Czq9IFUy.js";window.showAdminLogin=()=>{document.getElementById("adminModal").classList.remove("hidden")};window.hideAdminLogin=()=>{document.getElementById("adminModal").classList.add("hidden")};window.login=async()=>{const t=document.getElementById("adminUser").value,d=document.getElementById("adminPass").value,n=document.querySelector("#adminModal .btn-primary"),e=document.getElementById("errorMsg");n.innerText="Loading...",e.style.display="none";const s=await o("superAdminLogin",{username:t,password:d});s.success?(localStorage.setItem("superadmin_auth","true"),window.location.href="/super-admin/"):(e.innerText=s.message,e.style.display="block",n.innerText="Login")};
